import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { 
  LucideAngularModule, 
  MessageSquare, 
  Plus, 
  Paperclip, 
  ArrowUp, 
  ShieldCheck, 
  CreditCard, 
  RefreshCw, 
  FileText, 
  Globe 
} from '@lucide/angular';

@Component({
  selector: 'app-chat',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './chat.component.html',
  styleUrls: ['./chat.component.scss']
})
export class ChatComponent {
  inputText: string = '';
  
  // Icônes pour le template
  iconMessage = MessageSquare;
  iconPlus = Plus;
  iconPaperclip = Paperclip;
  iconArrow = ArrowUp;
  iconShield = ShieldCheck;

  // Suggestions de l'interface d'accueil
  suggestions = [
    { title: "Consulter les factures", desc: "Afficher les derniers impayés", icon: FileText, iconColor: 'text-amber-400' },
    { title: "Faire un transfert", desc: "Transférer des fonds ou un virement", icon: RefreshCw, iconColor: 'text-purple-400' },
    { title: "Vérifier un débit", desc: "Analyser une opération sortante", icon: CreditCard, iconColor: 'text-blue-400' },
    { title: "Support Multilingue", desc: "Parler en n'importe quelle langue", icon: Globe, iconColor: 'text-emerald-400' },
  ];

  sendMessage() {
    if (!this.inputText.trim()) return;
    
    console.log("Texte envoyé à l'agent DWEXO :", this.inputText);
    // TODO: Envoyer la chaîne brute au backend Python. 
    // Le LLM se chargera de classifier (DÉBIT / CRÉDIT / TRANSFERT) et de répondre dans la bonne langue.
    
    this.inputText = ''; // Reset du champ
  }

  selectSuggestion(title: string) {
    this.inputText = `Je souhaite ${title.toLowerCase()}`;
  }
}
